import{_ as n,o as s,c as e,a2 as i}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"Junie CLI — Benchmarks","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/junie-cli/benchmarks.md","filePath":"research/agents/junie-cli/benchmarks.md"}'),t={name:"research/agents/junie-cli/benchmarks.md"};function l(p,a,o,r,c,d){return s(),e("div",null,[...a[0]||(a[0]=[i(`<h1 id="junie-cli-—-benchmarks" tabindex="-1">Junie CLI — Benchmarks <a class="header-anchor" href="#junie-cli-—-benchmarks" aria-label="Permalink to &quot;Junie CLI — Benchmarks&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Junie&#39;s benchmark performance provides concrete evidence for its architectural choices, particularly the multi-model routing strategy. While Junie is a relatively new entrant in the CLI agent space (CLI mode added June 2025), its Terminal-Bench 2.0 results place it among the top performers — and the comparison between its multi-model and single-model configurations offers unique insight into the value of intelligent model selection.</p><p>This document analyzes Junie&#39;s benchmark results, interprets the multi-model uplift, and contextualizes its performance within the broader agent landscape.</p><h2 id="terminal-bench-2-0-results" tabindex="-1">Terminal-Bench 2.0 Results <a class="header-anchor" href="#terminal-bench-2-0-results" aria-label="Permalink to &quot;Terminal-Bench 2.0 Results&quot;">​</a></h2><h3 id="primary-results" tabindex="-1">Primary Results <a class="header-anchor" href="#primary-results" aria-label="Permalink to &quot;Primary Results&quot;">​</a></h3><p>Terminal-Bench 2.0 is a benchmark specifically designed to evaluate CLI coding agents on real-world terminal-based programming tasks. Junie has two entries:</p><table tabindex="0"><thead><tr><th>Configuration</th><th>Score</th><th>Rank</th><th>Notes</th></tr></thead><tbody><tr><td>Junie (Multiple Models)</td><td>71.0%</td><td>#14</td><td>Multi-model orchestration</td></tr><tr><td>Junie (Gemini 3 Flash)</td><td>64.3%</td><td>#25</td><td>Single model baseline</td></tr></tbody></table><h3 id="performance-context" tabindex="-1">Performance Context <a class="header-anchor" href="#performance-context" aria-label="Permalink to &quot;Performance Context&quot;">​</a></h3><p>To contextualize Junie&#39;s results, here&#39;s where it falls in the broader rankings:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Terminal-Bench 2.0 Approximate Landscape:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Top Tier (75%+):</span></span>
<span class="line"><span>  Rank ~1-8: Leading agents with best model configurations</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Upper-Mid Tier (70-75%):</span></span>
<span class="line"><span>  Rank ~9-16: Strong performers</span></span>
<span class="line"><span>  ★ Junie (Multiple Models) at 71.0% — Rank #14</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Mid Tier (60-70%):</span></span>
<span class="line"><span>  Rank ~17-30: Capable agents</span></span>
<span class="line"><span>  ★ Junie (Gemini 3 Flash) at 64.3% — Rank #25</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Lower Tier (&lt;60%):</span></span>
<span class="line"><span>  Rank ~31+: Developing agents or limited configurations</span></span></code></pre></div><h3 id="what-the-rankings-mean" tabindex="-1">What the Rankings Mean <a class="header-anchor" href="#what-the-rankings-mean" aria-label="Permalink to &quot;What the Rankings Mean&quot;">​</a></h3><p><strong>Rank #14 (71.0%, Multi-Model)</strong>:</p><ul><li>Places Junie in the upper-mid tier of CLI agents</li><li>Competitive with well-established agents</li><li>Demonstrates that JetBrains&#39; IDE heritage and multi-model approach translate to real terminal-based task performance</li><li>Notably strong for a relatively new CLI entrant</li></ul><p><strong>Rank #25 (64.3%, Gemini 3 Flash)</strong>:</p><ul><li>Places single-model Junie in the mid tier</li><li>Gemini 3 Flash is a fast, cost-effective model — not the strongest</li><li>Serves as a valuable baseline for measuring multi-model uplift</li><li>Still competitive, showing the agent framework itself has value</li></ul><h2 id="multi-model-uplift-analysis" tabindex="-1">Multi-Model Uplift Analysis <a class="header-anchor" href="#multi-model-uplift-analysis" aria-label="Permalink to &quot;Multi-Model Uplift Analysis&quot;">​</a></h2><h3 id="the-key-finding" tabindex="-1">The Key Finding <a class="header-anchor" href="#the-key-finding" aria-label="Permalink to &quot;The Key Finding&quot;">​</a></h3><p>The difference between Junie&#39;s multi-model and single-model results is the most analytically interesting aspect of its benchmark performance:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Multi-Model Score:     71.0%</span></span>
<span class="line"><span>Single-Model Score:    64.3%</span></span>
<span class="line"><span>━━━━━━━━━━━━━━━━━━━━━━━━━━━</span></span>
<span class="line"><span>Absolute Uplift:       +6.7 percentage points</span></span>
<span class="line"><span>Relative Uplift:       +10.4% improvement</span></span>
<span class="line"><span>Rank Improvement:      +11 positions (#25 → #14)</span></span></code></pre></div><h3 id="interpreting-the-6-7pp-uplift" tabindex="-1">Interpreting the 6.7pp Uplift <a class="header-anchor" href="#interpreting-the-6-7pp-uplift" aria-label="Permalink to &quot;Interpreting the 6.7pp Uplift&quot;">​</a></h3><h4 id="task-level-analysis" tabindex="-1">Task-Level Analysis <a class="header-anchor" href="#task-level-analysis" aria-label="Permalink to &quot;Task-Level Analysis&quot;">​</a></h4><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>In a 100-task benchmark:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Single model succeeds:           ~64 tasks</span></span>
<span class="line"><span>Single model fails:              ~36 tasks</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Multi-model succeeds:            ~71 tasks</span></span>
<span class="line"><span>Multi-model fails:               ~29 tasks</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Tasks recovered by multi-model:  ~7 tasks</span></span>
<span class="line"><span>Recovery rate:                   ~19.4% of single-model failures</span></span></code></pre></div><p>This means that for roughly 1 in 5 tasks where the single model fails, the multi-model routing recovers a success. This is a substantial improvement that validates the architectural complexity of multi-model orchestration.</p><h4 id="where-does-the-uplift-come-from" tabindex="-1">Where Does the Uplift Come From? <a class="header-anchor" href="#where-does-the-uplift-come-from" aria-label="Permalink to &quot;Where Does the Uplift Come From?&quot;">​</a></h4><p>The 6.7pp uplift likely comes from several task categories:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>1. Complex Reasoning Tasks (~2-3pp contribution)</span></span>
<span class="line"><span>   - Tasks requiring multi-step planning</span></span>
<span class="line"><span>   - The reasoning model (likely Claude Opus or similar) handles</span></span>
<span class="line"><span>     these better than Gemini Flash</span></span>
<span class="line"><span>   - Example: &quot;Refactor this module to use the strategy pattern&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Language-Specific Tasks (~1-2pp contribution)</span></span>
<span class="line"><span>   - Tasks where one model is notably better for a specific language</span></span>
<span class="line"><span>   - Example: Claude may be better at Rust, GPT at TypeScript</span></span>
<span class="line"><span>   - Routing to the best model per language adds marginal gains</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. Debugging/Diagnosis Tasks (~1-2pp contribution)</span></span>
<span class="line"><span>   - Tasks requiring careful analysis of error messages and code</span></span>
<span class="line"><span>   - Reasoning models excel at root cause analysis</span></span>
<span class="line"><span>   - Gemini Flash may miss subtle issues</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. Large Context Tasks (~1pp contribution)</span></span>
<span class="line"><span>   - Tasks requiring many files in context</span></span>
<span class="line"><span>   - Using a model with larger context window when needed</span></span>
<span class="line"><span>   - Gemini Flash may truncate critical context</span></span></code></pre></div><h3 id="statistical-significance" tabindex="-1">Statistical Significance <a class="header-anchor" href="#statistical-significance" aria-label="Permalink to &quot;Statistical Significance&quot;">​</a></h3><p>With a 6.7pp difference on a benchmark of meaningful size:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Assuming ~100 tasks:</span></span>
<span class="line"><span>  Observed difference: 6.7pp</span></span>
<span class="line"><span>  Standard error: ~4.7pp (binomial approximation)</span></span>
<span class="line"><span>  Z-score: ~1.43</span></span>
<span class="line"><span>  p-value: ~0.076</span></span>
<span class="line"><span></span></span>
<span class="line"><span>This is marginally significant at the 0.10 level but not at 0.05.</span></span>
<span class="line"><span>With more tasks or larger effect sizes, significance would be clearer.</span></span></code></pre></div><p>However, the 11-rank improvement provides additional evidence that the uplift is meaningful, not just noise.</p><h3 id="cost-benefit-of-multi-model-routing" tabindex="-1">Cost-Benefit of Multi-Model Routing <a class="header-anchor" href="#cost-benefit-of-multi-model-routing" aria-label="Permalink to &quot;Cost-Benefit of Multi-Model Routing&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Benefits:</span></span>
<span class="line"><span>  ✅ +6.7pp absolute performance improvement</span></span>
<span class="line"><span>  ✅ +11 rank positions</span></span>
<span class="line"><span>  ✅ ~19% failure recovery rate</span></span>
<span class="line"><span>  ✅ Better handling of diverse task types</span></span>
<span class="line"><span>  ✅ Can optimize cost by using cheaper models for simple tasks</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Costs:</span></span>
<span class="line"><span>  ⚠️ Increased latency from model routing decisions</span></span>
<span class="line"><span>  ⚠️ Complexity in context routing between models</span></span>
<span class="line"><span>  ⚠️ Potential for inconsistency at model boundaries</span></span>
<span class="line"><span>  ⚠️ Higher aggregate API costs (multiple providers)</span></span>
<span class="line"><span>  ⚠️ Server-side infrastructure required for routing</span></span></code></pre></div><h2 id="comparison-with-other-agents" tabindex="-1">Comparison with Other Agents <a class="header-anchor" href="#comparison-with-other-agents" aria-label="Permalink to &quot;Comparison with Other Agents&quot;">​</a></h2><h3 id="multi-model-vs-single-model-agents" tabindex="-1">Multi-Model vs Single-Model Agents <a class="header-anchor" href="#multi-model-vs-single-model-agents" aria-label="Permalink to &quot;Multi-Model vs Single-Model Agents&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Configuration</th><th>Score</th><th>Multi-Model?</th></tr></thead><tbody><tr><td>Junie</td><td>Multiple Models</td><td>71.0%</td><td>✅ Yes</td></tr><tr><td>Junie</td><td>Gemini 3 Flash</td><td>64.3%</td><td>❌ No</td></tr></tbody></table><p>The comparison illustrates a key architectural question: <strong>Is multi-model routing worth the complexity?</strong></p><p>Junie&#39;s results suggest <strong>yes</strong>, at least at the current state of LLM capabilities where models have meaningfully different strengths and weaknesses.</p><h3 id="junie-s-competitive-advantages-in-benchmarks" tabindex="-1">Junie&#39;s Competitive Advantages in Benchmarks <a class="header-anchor" href="#junie-s-competitive-advantages-in-benchmarks" aria-label="Permalink to &quot;Junie&#39;s Competitive Advantages in Benchmarks&quot;">​</a></h3><ol><li><p><strong>Framework-aware task execution</strong>: Junie&#39;s knowledge of build systems and test frameworks reduces friction on tasks that require building or testing</p></li><li><p><strong>Test-driven verification</strong>: Automatic test execution catches regressions that other agents might miss</p></li><li><p><strong>Multi-model routing</strong>: Selects the best model for each sub-task</p></li><li><p><strong>Project structure understanding</strong>: Quickly identifies relevant files and project conventions</p></li></ol><h3 id="potential-benchmark-limitations" tabindex="-1">Potential Benchmark Limitations <a class="header-anchor" href="#potential-benchmark-limitations" aria-label="Permalink to &quot;Potential Benchmark Limitations&quot;">​</a></h3><p>When interpreting Junie&#39;s benchmark results, consider:</p><ol><li><p><strong>Benchmark-specific optimization</strong>: JetBrains may have optimized model routing specifically for Terminal-Bench task types</p></li><li><p><strong>Model availability</strong>: The specific models available to Junie during benchmarking affect results; newer models may change the ranking</p></li><li><p><strong>Cost comparison</strong>: Multi-model routing may cost more per task than single-model agents — benchmark scores don&#39;t capture cost efficiency</p></li><li><p><strong>Latency</strong>: Multi-model routing adds overhead; benchmarks don&#39;t typically measure time-to-completion</p></li><li><p><strong>Reproducibility</strong>: Closed-source nature means results can&#39;t be independently verified with the same configuration</p></li></ol><h2 id="model-specific-analysis" tabindex="-1">Model-Specific Analysis <a class="header-anchor" href="#model-specific-analysis" aria-label="Permalink to &quot;Model-Specific Analysis&quot;">​</a></h2><h3 id="gemini-3-flash-configuration-64-3" tabindex="-1">Gemini 3 Flash Configuration (64.3%) <a class="header-anchor" href="#gemini-3-flash-configuration-64-3" aria-label="Permalink to &quot;Gemini 3 Flash Configuration (64.3%)&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Strengths:</span></span>
<span class="line"><span>  - Fast response times (Flash is optimized for speed)</span></span>
<span class="line"><span>  - Cost-effective (cheaper per token than frontier models)</span></span>
<span class="line"><span>  - Good general coding capability</span></span>
<span class="line"><span>  - Large context window</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Weaknesses:</span></span>
<span class="line"><span>  - Not as strong on complex reasoning tasks</span></span>
<span class="line"><span>  - May miss subtle bugs in debugging scenarios</span></span>
<span class="line"><span>  - Less capable on certain languages compared to Claude/GPT</span></span>
<span class="line"><span>  - Single-model approach misses task-specific optimization</span></span></code></pre></div><h3 id="multiple-models-configuration-71-0" tabindex="-1">Multiple Models Configuration (71.0%) <a class="header-anchor" href="#multiple-models-configuration-71-0" aria-label="Permalink to &quot;Multiple Models Configuration (71.0%)&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Likely Model Mix:</span></span>
<span class="line"><span>  - Claude (Sonnet/Opus): Complex reasoning, debugging</span></span>
<span class="line"><span>  - GPT (4/4o): Balanced coding tasks</span></span>
<span class="line"><span>  - Gemini (Flash/Pro): Fast edits, simple tasks</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>Routing Strategy:</span></span>
<span class="line"><span>  - Planning → Strongest reasoning model</span></span>
<span class="line"><span>  - Implementation → Best model for the language/task</span></span>
<span class="line"><span>  - Debugging → Strong analytical model</span></span>
<span class="line"><span>  - Simple edits → Fastest available model</span></span></code></pre></div><h2 id="benchmark-evolution-and-predictions" tabindex="-1">Benchmark Evolution and Predictions <a class="header-anchor" href="#benchmark-evolution-and-predictions" aria-label="Permalink to &quot;Benchmark Evolution and Predictions&quot;">​</a></h2><h3 id="historical-context" tabindex="-1">Historical Context <a class="header-anchor" href="#historical-context" aria-label="Permalink to &quot;Historical Context&quot;">​</a></h3><ul><li><strong>April 2025</strong>: Junie reaches general availability (IDE mode)</li><li><strong>June 2025</strong>: CLI mode launched</li><li><strong>Terminal-Bench 2.0</strong>: First major CLI benchmark appearance</li></ul><h3 id="performance-trajectory-predictions" tabindex="-1">Performance Trajectory Predictions <a class="header-anchor" href="#performance-trajectory-predictions" aria-label="Permalink to &quot;Performance Trajectory Predictions&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Factors That May Improve Junie&#39;s Scores:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Routing Optimization</span></span>
<span class="line"><span>   - JetBrains can A/B test routing strategies server-side</span></span>
<span class="line"><span>   - Continuous improvement without agent updates</span></span>
<span class="line"><span>   - Learning from aggregated task success/failure data</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. New Model Integration</span></span>
<span class="line"><span>   - As new models launch, Junie can add them to its routing</span></span>
<span class="line"><span>   - Each new model potentially adds task coverage</span></span>
<span class="line"><span>   - JetBrains can quickly integrate new providers</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. IDE Knowledge Transfer</span></span>
<span class="line"><span>   - More IDE-derived heuristics can be ported to CLI mode</span></span>
<span class="line"><span>   - Better project structure analysis</span></span>
<span class="line"><span>   - Enhanced test framework support</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. Agent Core Improvements</span></span>
<span class="line"><span>   - Better planning algorithms</span></span>
<span class="line"><span>   - Improved tool use strategies</span></span>
<span class="line"><span>   - Enhanced context management</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Factors That May Limit Growth:</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. Benchmark Saturation</span></span>
<span class="line"><span>   - As scores approach 80-90%, marginal improvements are harder</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Routing Complexity</span></span>
<span class="line"><span>   - More models increase routing complexity and potential for errors</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. Competition</span></span>
<span class="line"><span>   - Other agents are also improving rapidly</span></span>
<span class="line"><span>   - Open-source agents benefit from community contributions</span></span></code></pre></div><h2 id="benchmark-methodology-notes" tabindex="-1">Benchmark Methodology Notes <a class="header-anchor" href="#benchmark-methodology-notes" aria-label="Permalink to &quot;Benchmark Methodology Notes&quot;">​</a></h2><h3 id="terminal-bench-2-0-characteristics" tabindex="-1">Terminal-Bench 2.0 Characteristics <a class="header-anchor" href="#terminal-bench-2-0-characteristics" aria-label="Permalink to &quot;Terminal-Bench 2.0 Characteristics&quot;">​</a></h3><p>Terminal-Bench 2.0 evaluates agents on:</p><ul><li>Real-world coding tasks executed in a terminal environment</li><li>Multiple programming languages and frameworks</li><li>Tasks ranging from simple edits to complex multi-file changes</li><li>Success measured by functional correctness (typically test passing)</li></ul><h3 id="considerations-for-interpretation" tabindex="-1">Considerations for Interpretation <a class="header-anchor" href="#considerations-for-interpretation" aria-label="Permalink to &quot;Considerations for Interpretation&quot;">​</a></h3><ol><li><p><strong>Benchmark ≠ Real World</strong>: Benchmark tasks are curated and may not represent the full diversity of real developer workflows</p></li><li><p><strong>Single Run vs Multi Run</strong>: Results may vary between runs due to LLM non-determinism</p></li><li><p><strong>Task Distribution</strong>: The specific mix of task types affects which agents perform best; different distributions would yield different rankings</p></li><li><p><strong>Environment Control</strong>: Benchmark environments may differ from real development environments in available tools, network access, etc.</p></li></ol><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ol><li><p><strong>Multi-model routing provides measurable uplift</strong>: The 6.7pp improvement from multi-model vs single-model is the strongest evidence we have for the value of intelligent model selection in coding agents.</p></li><li><p><strong>Junie is competitive as a new CLI entrant</strong>: Rank #14 in its first major benchmark appearance is impressive, especially given the agent&#39;s IDE origins.</p></li><li><p><strong>The JetBrains framework adds value beyond model selection</strong>: Even the single-model (Gemini Flash) configuration at Rank #25 shows that the agent framework itself (project understanding, test integration, etc.) contributes to performance.</p></li><li><p><strong>Server-side optimization is a competitive advantage</strong>: JetBrains&#39; ability to optimize model routing without agent updates creates a continuously improving system.</p></li><li><p><strong>Cost-performance trade-offs need more analysis</strong>: While multi-model routing improves accuracy, the cost and latency implications are not captured in benchmark scores.</p></li></ol>`,61)])])}const u=n(t,[["render",l]]);export{m as __pageData,u as default};
